{"operationName":"ReviewStats_Init","variables":{"skuId":"6458343"},"extensions":{"clientLibrary":{"name":"@apollo/client","version":"4.1.6"}},"query":"query ReviewStats_Init($skuId: String!, $openBoxCondition: Int) {
  productBySkuId(skuId: $skuId, openBoxCondition: $openBoxCondition) {
    ...ReviewStats_Fragment
    __typename
    skuId
    openBoxCondition
  }
}

fragment ReviewStats_Fragment on Product {
  skuId
  orderCode
  reviewInfo {
    averageRating
    reviewCount
    syndicatedReviewSummary {
      clientDisplayName
      overallRating
      totalReviewCount
      displayLink
      __typename
    }
    __typename
  }
  url {
    relativePdp
    skuSpecificUrl
    __typename
  }
  name {
    short
    __typename
  }
  __typename
  openBoxCondition
}"}
